    let z = zIn;
    let zTerm: *const u8 = if nByte >= 0 {
        unsafe { z.add(nByte as usize) }
    } else {
        (-1i32) as *const u8
    };

    let mut pos = 0usize;
    loop {
        unsafe {
            let current_byte = *z.add(pos);
            if current_byte == 0 || z.add(pos) >= zTerm {
                break;
            }

            let b = current_byte;
            if b < 0x80 {
                pos += 1;
            } else if (b & 0xE0) == 0xC0 {
                pos += 2;
            } else if (b & 0xF0) == 0xE0 {
                pos += 3;
            } else if (b & 0xF8) == 0xF0 {
                pos += 4;
            } else {
                pos += 1;
            }
        }

        r = r.wrapping_add(1);
    }

    r
}

