unsafe fn sqlite3_strnicmp(a: *const u8, b: *const u8, n: i32) -> i32 {
    for i in 0..n {
        let ca = (*a.offset(i as isize)).to_ascii_lowercase();
        let cb = (*b.offset(i as isize)).to_ascii_lowercase();
        if ca != cb {
            return if ca < cb { -1 } else { 1 };
        }
    }
    0
}

