#[no_mangle]
pub extern "C" fn json5Whitespace(zIn: *const u8) -> i32 {
    unsafe {
        let mut n: i32 = 0;
        let z = zIn;

        loop {
            let byte = *z.offset(n as isize);

            match byte {
                0x09 | 0x0a | 0x0b | 0x0c | 0x0d | 0x20 => {
                    n += 1;
                }
                b'/' => {
                    let next = *z.offset((n + 1) as isize);
                    let next_next = *z.offset((n + 2) as isize);

                    if next == b'*' && next_next != 0 {
                        let mut j = n + 3;
                        loop {
                            let curr = *z.offset(j as isize);
                            let prev = *z.offset((j - 1) as isize);
                            if curr == 0 {
                                return n;
                            }
                            if curr == b'/' && prev == b'*' {
                                break;
                            }
                            j += 1;
                        }
                        n = j + 1;
                    } else if next == b'/' {
                        let mut j = n + 2;
                        loop {
                            let c = *z.offset(j as isize);
                            if c == 0 {
                                break;
                            }
                            if c == b'\n' || c == b'\r' {
                                break;
                            }
                            if c == 0xe2
                                && *z.offset((j + 1) as isize) == 0x80
                                && (*z.offset((j + 2) as isize) == 0xa8
                                    || *z.offset((j + 2) as isize) == 0xa9)
                            {
                                j += 2;
                                break;
                            }
                            j += 1;
                        }
                        n = j;
                        if *z.offset(n as isize) != 0 {
                            n += 1;
                        }
                    } else {
                        return n;
                    }
                }
                0xc2 => {
                    if *z.offset((n + 1) as isize) == 0xa0 {
                        n += 2;
                    } else {
                        return n;
                    }
                }
                0xe1 => {
                    if *z.offset((n + 1) as isize) == 0x9a
                        && *z.offset((n + 2) as isize) == 0x80
                    {
                        n += 3;
                    } else {
                        return n;
                    }
                }
                0xe2 => {
                    let b1 = *z.offset((n + 1) as isize);
                    if b1 == 0x80 {
                        let c = *z.offset((n + 2) as isize);
                        if c < 0x80 {
                            return n;
                        }
                        if c <= 0x8a || c == 0xa8 || c == 0xa9 || c == 0xaf {
                            n += 3;
                        } else {
                            return n;
                        }
                    } else if b1 == 0x81 && *z.offset((n + 2) as isize) == 0x9f {
                        n += 3;
                    } else {
                        return n;
                    }
                }
                0xe3 => {
                    if *z.offset((n + 1) as isize) == 0x80
                        && *z.offset((n + 2) as isize) == 0x80
                    {
                        n += 3;
                    } else {
                        return n;
                    }
                }
                0xef => {
                    if *z.offset((n + 1) as isize) == 0xbb
                        && *z.offset((n + 2) as isize) == 0xbf
                    {
                        n += 3;
                    } else {
                        return n;
                    }
                }
                _ => {
                    return n;
                }
            }
        }
    }
}

#[no_mangle]
pub extern "C" fn jsonAllAlphanum(z: *const u8, n: i32) -> i32 {
    if n < 0 {
        return 0;
    }

    let n_usize = n as usize;
    let mut i = 0;

    while i < n_usize {
        unsafe {
            let byte = *z.add(i);
            // sqlite3Isalnum checks if (sqlite3CtypeMap[byte] & 0x06) is nonzero
            // We need to check if byte is alphanumeric or underscore
            let is_alnum = (byte >= b'0' && byte <= b'9') ||
                           (byte >= b'A' && byte <= b'Z') ||
                           (byte >= b'a' && byte <= b'z');

            if is_alnum || byte == b'_' {
                i += 1;
            } else {
                break;
            }
        }
    }

    if i == n_usize { 1 } else { 0 }
}

#[no_mangle]
pub extern "C" fn jsonBytesToBypass(z: *const u8, n: u32) -> u32 {
    let mut i: u32 = 0;

    while i.wrapping_add(1) < n {
        if z.is_null() {
            return i;
        }

        unsafe {
            let byte_i = *z.add(i as usize);

            if byte_i != b'\\' {
                return i;
            }

            let byte_i1 = *z.add(i.wrapping_add(1) as usize);

            if byte_i1 == b'\n' {
                i = i.wrapping_add(2);
                continue;
            }

            if byte_i1 == b'\r' {
                if i.wrapping_add(2) < n {
                    let byte_i2 = *z.add(i.wrapping_add(2) as usize);
                    if byte_i2 == b'\n' {
                        i = i.wrapping_add(3);
                    } else {
                        i = i.wrapping_add(2);
                    }
                } else {
                    i = i.wrapping_add(2);
                }
                continue;
            }

            if byte_i1 == 0xe2
                && i.wrapping_add(3) < n
            {
                let byte_i2 = *z.add(i.wrapping_add(2) as usize);
                let byte_i3 = *z.add(i.wrapping_add(3) as usize);
                if byte_i2 == 0x80 && (byte_i3 == 0xa8 || byte_i3 == 0xa9) {
                    i = i.wrapping_add(4);
                    continue;
                }
            }
        }

        break;
    }

    i
}

