#[no_mangle]
pub extern "C" fn nocaseCollatingFunc(NotUsed: *mut u8, nKey1: i32, pKey1: *const u8, nKey2: i32, pKey2: *const u8) -> i32 {
    let _ = NotUsed;

    let len = if nKey1 < nKey2 { nKey1 } else { nKey2 };

    let mut r = 0i32;

    if len > 0 {
        unsafe {
            let s1 = std::slice::from_raw_parts(pKey1, len as usize);
            let s2 = std::slice::from_raw_parts(pKey2, len as usize);

            for i in 0..(len as usize) {
                let c1 = s1[i].to_ascii_lowercase() as i32;
                let c2 = s2[i].to_ascii_lowercase() as i32;
                if c1 != c2 {
                    r = c1 - c2;
                    break;
                }
            }
        }
    }

    if r == 0 {
        r = nKey1.wrapping_sub(nKey2);
    }

    r
}

