#[no_mangle]
pub extern "C" fn vdbeRecordDecodeInt(serial_type: u32, aKey: *const u8) -> i64 {
    if aKey.is_null() {
        return 0;
    }

    match serial_type {
        0 | 1 => {
            unsafe {
                *aKey as i8 as i64
            }
        }
        2 => {
            unsafe {
                let b0 = *aKey as i8 as i64;
                let b1 = *aKey.add(1) as i64;
                b0 * 256 + b1
            }
        }
        3 => {
            unsafe {
                let b0 = *aKey as i8 as i64;
                let b1 = *aKey.add(1) as i64;
                let b2 = *aKey.add(2) as i64;
                b0 * 65536 + (b1 << 8) + b2
            }
        }
        4 => {
            unsafe {
                let b0 = (*aKey as u32) << 24;
                let b1 = (*aKey.add(1) as u32) << 16;
                let b2 = (*aKey.add(2) as u32) << 8;
                let b3 = *aKey.add(3) as u32;
                let y = b0 | b1 | b2 | b3;
                (y as i32) as i64
            }
        }
        5 => {
            unsafe {
                let b0 = *aKey as i8 as i64;
                let b1 = *aKey.add(1) as i64;
                let b2 = (*aKey.add(2) as u32) << 24;
                let b3 = (*aKey.add(3) as u32) << 16;
                let b4 = (*aKey.add(4) as u32) << 8;
                let b5 = *aKey.add(5) as u32;
                let upper = b0 * 256 + b1;
                let lower = (b2 | b3 | b4 | b5) as i64;
                lower + (upper << 32)
            }
        }
        6 => {
            unsafe {
                let b0 = (*aKey as u32) << 24;
                let b1 = (*aKey.add(1) as u32) << 16;
                let b2 = (*aKey.add(2) as u32) << 8;
                let b3 = *aKey.add(3) as u32;
                let x_hi = b0 | b1 | b2 | b3;

                let b4 = (*aKey.add(4) as u32) << 24;
                let b5 = (*aKey.add(5) as u32) << 16;
                let b6 = (*aKey.add(6) as u32) << 8;
                let b7 = *aKey.add(7) as u32;
                let x_lo = b4 | b5 | b6 | b7;

                let x = ((x_hi as u64) << 32) | (x_lo as u64);
                x as i64
            }
        }
        _ => {
            (serial_type as i64) - 8
        }
    }
}

